import akka.actor.{Actor, ActorSystem, Props}

case class Deposit(amount: Double)
case class Withdraw(amount: Double)
case object GetBalance

class AccountActor extends Actor {
  private var balance: Double = 0.0

  def receive: Receive = {
    case Deposit(amount) =>
      balance += amount
      sender() ! s"Deposited $amount, new balance: $balance"

    case Withdraw(amount) =>
      if (balance >= amount) {
        balance -= amount
        sender() ! s"Withdrew $amount, new balance: $balance"
      } else {
        sender() ! s"Insufficient funds, current balance: $balance"
      }

    case GetBalance =>
      sender() ! s"Current balance: $balance"
  }
}

object AccountApp extends App {
  val system = ActorSystem("AccountSystem")
  val accountActor = system.actorOf(Props[AccountActor], "accountActor")

  // Example usage
  import akka.pattern.ask
  import akka.util.Timeout
  import scala.concurrent.duration._
  import scala.concurrent.ExecutionContext.Implicits.global

  implicit val timeout: Timeout = Timeout(5.seconds)

  accountActor ! Deposit(100)
  accountActor ! Withdraw(50)
  accountActor ! Withdraw(60)

  (accountActor ? GetBalance).foreach(println)
}